// Two actions:
//   approve_registration: { request_id, assigned_id, salary, level, notes, status='идэвхтэй', approved_by, approved_at }
//   reject_registration:  { request_id, status='татгалзсан', rejected_by, rejected_at }
const body = $input.first().json.body || {};
const action = body.action;
if (!['approve_registration','reject_registration'].includes(action)) {
  return [{ json: { ok: false, error: 'Unknown action' } }];
}
if (!body.request_id) {
  return [{ json: { ok: false, error: 'Missing request_id' } }];
}
const isApprove = action === 'approve_registration';
const row = {
  // Match column — Хүсэлтийн ID
  'Хүсэлтийн ID': String(body.request_id),
  // Шинэчлэгдэх багана
  'Төлөв': body.status || (isApprove ? 'идэвхтэй' : 'татгалзсан'),
};
if (isApprove) {
  if (body.assigned_id) row['ID'] = String(body.assigned_id).toUpperCase();
  if (body.salary != null) row['Цалин'] = String(body.salary);
  if (body.level != null) row['Зэрэглэл'] = Number(body.level) || 40;
  if (body.notes) row['CEO тэмдэглэл'] = body.notes;
  row['Орсон огноо'] = new Date().toISOString().slice(0, 10);
  row['Зөвшөөрсөн'] = body.approved_by || '';
  row['Зөвшөөрсөн огноо'] = body.approved_at || new Date().toISOString();
} else {
  row['Татгалзсан'] = body.rejected_by || '';
  row['Татгалзсан огноо'] = body.rejected_at || new Date().toISOString();
  if (body.reason) row['Татгалзах шалтгаан'] = body.reason;
}
return [{ json: row }];
